import { useState, useEffect, useCallback, useRef } from "react";

export interface Coin {
  id: string;
  symbol: string;
  name: string;
  image: string;
  current_price: number;
  market_cap: number;
  market_cap_rank: number;
  price_change_percentage_24h: number;
  total_volume: number;
  high_24h: number;
  low_24h: number;
}

const API_URL =
  "/api/proxy?url=" +
  encodeURIComponent(
    "https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&order=market_cap_desc&per_page=20&page=1&sparkline=false"
  );

export function useCoinData(refreshInterval = 60000) {
  const [coins, setCoins] = useState<Coin[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const fetchCoins = useCallback(async (isInitial = false) => {
    if (isInitial) setLoading(true);
    setError(null);

    try {
      const res = await fetch(API_URL);
      if (!res.ok) {
        throw new Error(
          res.status === 429
            ? "Rate limited by CoinGecko. Will retry shortly."
            : `Failed to fetch data (HTTP ${res.status})`
        );
      }
      const data: Coin[] = await res.json();
      setCoins(data);
      setLastUpdated(new Date());
    } catch (err: any) {
      setError(err.message || "An unexpected error occurred.");
    } finally {
      if (isInitial) setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchCoins(true);

    intervalRef.current = setInterval(() => fetchCoins(false), refreshInterval);

    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [fetchCoins, refreshInterval]);

  const retry = useCallback(() => {
    fetchCoins(true);
  }, [fetchCoins]);

  return { coins, loading, error, lastUpdated, retry };
}

