import React from "react";
import { TrendingUp, TrendingDown } from "lucide-react";
import type { Coin } from "../hooks/useCoinData";

function formatPrice(price: number): string {
  if (price >= 1) {
    return price.toLocaleString("en-US", {
      style: "currency",
      currency: "USD",
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });
  }
  return price.toLocaleString("en-US", {
    style: "currency",
    currency: "USD",
    minimumFractionDigits: 2,
    maximumFractionDigits: 6,
  });
}

function formatMarketCap(cap: number): string {
  if (cap >= 1e12) return `$${(cap / 1e12).toFixed(2)}T`;
  if (cap >= 1e9) return `$${(cap / 1e9).toFixed(2)}B`;
  if (cap >= 1e6) return `$${(cap / 1e6).toFixed(2)}M`;
  return `$${cap.toLocaleString()}`;
}

interface CoinRowProps {
  coin: Coin;
}

export const CoinRow: React.FC<CoinRowProps> = React.memo(({ coin }) => {
  const change = coin.price_change_percentage_24h ?? 0;
  const isPositive = change >= 0;

  return (
    <div className="grid grid-cols-[2rem_1fr_6.5rem_7rem_6.5rem] sm:grid-cols-[2rem_1fr_7rem_8rem_8rem] items-center gap-3 px-3 py-2.5 border-b border-zinc-800/60 hover:bg-zinc-800/40 transition-colors">
      {/* Rank + Logo */}
      <span className="text-zinc-500 text-xs text-right tabular-nums">
        {coin.market_cap_rank}
      </span>

      {/* Name + Symbol */}
      <div className="flex items-center gap-2.5 min-w-0">
        <img
          src={coin.image}
          alt={coin.name}
          className="w-6 h-6 shrink-0"
          loading="lazy"
        />
        <div className="flex items-center gap-1.5 min-w-0">
          <span className="text-zinc-100 text-sm font-medium truncate">
            {coin.name}
          </span>
          <span className="text-zinc-500 text-xs uppercase shrink-0">
            {coin.symbol}
          </span>
        </div>
      </div>

      {/* Price */}
      <span className="text-zinc-100 text-sm text-right tabular-nums">
        {formatPrice(coin.current_price)}
      </span>

      {/* 24h Change */}
      <div
        className={`flex items-center justify-end gap-1 text-sm tabular-nums ${
          isPositive ? "text-emerald-400" : "text-red-400"
        }`}
      >
        {isPositive ? (
          <TrendingUp className="w-3.5 h-3.5 shrink-0" />
        ) : (
          <TrendingDown className="w-3.5 h-3.5 shrink-0" />
        )}
        <span>
          {isPositive ? "+" : ""}
          {change.toFixed(2)}%
        </span>
      </div>

      {/* Market Cap */}
      <span className="text-zinc-400 text-sm text-right tabular-nums">
        {formatMarketCap(coin.market_cap)}
      </span>
    </div>
  );
});

